+    ,.sb_fraw_dep_i((`COREPATH.be.detector.frs1_sb_raw_haz_v
+                   | `COREPATH.be.detector.frs2_sb_raw_haz_v
+                   | `COREPATH.be.detector.frs3_sb_raw_haz_v
